VALUES
  ('promotion-6f0ba476-moex-00225', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '乙公司於X1年1月1日按公允價值$798,577購入一剩餘存續期間為4年，合約現金流量分別 為每年底$500,000之債務工具，該債務工具為信用減損之金融資產，並將該債務工具分類為按 攤銷後成本衡量，該債務工具之信用調整後有效利率為4%。乙公司評估該債務工具未來4年 每年底預期收取之現金流量皆為$220,000。X1年12月31日乙公司收到$220,000，並評估債務 工具發行人之信用狀況已稍有改善，但仍屬信用減損之金融資產，估計未來每年預期收取之現 金流量分別為$250,000。試問前述交易對X1年度損益之淨影響為何？（不考慮所得稅之影響， 四捨五入取至元）', '["$(661,830)", "$31,943", "$83,253", "$115,196"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00226', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '承上題，乙公司於 X2 年 12 月 31 日收到$250,000，並評估債務工具發行人之信用狀況將惡 化，估計未來每年預期收取之現金流量分別為$200,000。試問前述交易對X2年度損益之淨影 響為何？（不考慮所得稅之影響，四捨五入取至元）', '["$24,421", "$27,751", "$(66,554)", "$(69,884)"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00227', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年12月31日按公允價值$500,000購入一債券，面額$500,000，票面利率5%， 每年底付息 1 次，5 年到期，原按其經營模式分類為透過損益按公允價值衡量之金融資產。 至X3年12月31日，甲公司因改變其管理債券之經營模式，決定重分類該債券。該債券於 重分類日之公允價值為$490,000，經評估之12個月預期信用損失為$4,000，存續期間預期信 用損失為$7,000。X4年底該債券之公允價值為$520,000，備抵損失餘額為$5,000。試問若將該 債券重分類為按攤銷後成本衡量或透過其他綜合損益按公允價值衡量，則兩種情況下 X4 年 度本期損益之差異為：（假設該債券並非信用減損之金融資產，不考慮所得稅之影響，四捨五 入取至元）', '["$0", "$10,000", "$26,825", "$36,825"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00228', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', 'X1年初，甲公司給予總經理10,000股認股權，既得條件除繼續服務至X4年底外，關於績效 亦有要求，以下為二種獨立的績效條件情境：第一種情境：甲公司股價X4年底必須超過$65； 第二種情境：X4年底前，每年度營業收入成長率均必須超過8%。若滿足既得條件後，則於後 續4年內可執行該認股權利。若未滿足既得條件，認股權將失效。假設兩種績效條件情境下所 估計之每股認股權公允價值均為$25。若X4年底，甲公司股價僅為$60，前三年營收成長率均 超過8%，但X4年僅為5%，對於該認股權X4年相關之會計處理，下列敘述何者正確？', '["在第一種情境下，資本公積減少", "在第二種情境下，薪資費用增加", "在第一種情境下，資本公積增加", "在第二種情境下，薪資費用減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00229', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司X3年初向銀行舉借$100,000，X5年12月31日到期，利率6%，以分期還款方式於每 年6月30日、12月31日支付$18,460。X4年12月31日之資產負債表中資產總額為$360,000， 試問X4年底該筆負債對資產比為多少？（答案四捨五入至小數點第4位）', '["9.81%", "11.03%", "17.52%", "19.06%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00230', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '對於屬製造業之承租人與出租人，下列項目中最多有幾項屬於現金流量表之營業活動現金流 量？⑴承租人於短期租賃中支付之租金 ⑵出租人於營業租賃中收取之租金 ⑶非製造商或 經銷商之出租人於融資租賃中收取應收租賃款之本金 ⑷承租人對使用權資產提列之折舊 ⑸製造商或經銷商之出租人於融資租賃中收取應收租賃款之本金 ⑹製造商或經銷商之出租 人於融資租賃中收取應收租賃款之利息', '["3項", "4項", "5項", "6項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00231', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司20X1年1月1日與乙公司簽訂銷售A產品之合約，依合約約定每個產品之售價為$100， 惟若乙公司於1年內購買A產品超過10,000個，則全年之每個產品售價為$90。20X1年第1 季，乙公司購買1,000個A產品，甲公司估計乙公司全年購買量不會超過10,000個，第1季已 認列相關之銷貨收入。20X1年第2季，乙公司因大幅擴店，全季共購買5,000個A產品，甲 公司估計乙公司全年購買量將超過10,000個，試問甲公司第2季應認列之銷貨收入為何？', '["$440,000", "$450,000", "$490,000", "$500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00232', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '有關客戶合約之收入，下列3項敘述正確的有幾項？ ⑴企業已自客戶收取對價而須移轉商品或勞務予客戶之義務為合約負債。 ⑵若合約中承諾之對價包括變動金額，企業應估計其移轉所承諾之商品或勞務予客戶以換得 有權取得之對價金額。 ⑶企業應以相對單獨售價為基礎，將交易價格分攤至合約中辨認出之每一履約義務。', '["0項", "1項", "2項", "3項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00233', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司X2年1月1日的權益總額為$4,010,000，顯示特別股股本為$1,000,000（面額$100、 5%累積特別股）、普通股股本為$2,500,000（面額$10、流通在外股數200,000股）、特別股發 行溢價為$400,000、普通股發行溢價為$500,000、保留盈餘為$260,000與庫藏股票為$650,000。 X2年相關普通股交易為：2月1日以每股$13購買庫藏股15,000股，4月1日以每股$11出 售庫藏股12,000股，6月1日註銷53,000股的剩餘庫藏股票。甲公司於X2年度稅前淨利為 $240,000，稅率為20%。若甲公司X2年除前述交易之外並無其他影響權益之交易，請問X2 年底甲公司權益總額為何？', '["$4,012,000", "$4,235,000", "$4,139,000", "$4,151,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00234', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日給與1位高階主管10,000單位認股權，履約價格為$35，條件為該主 管必須繼續在公司服務滿3年，且認股權只有在公司股價於第3年底超過$75時才能執行。 甲公司考慮股價在第 3 年底超過$75 及未超過$75 的可能性後，估計認股權的公允價值為每 單位$30。X3年12月31日該主管仍繼續在公司服務，但甲公司當年底股票市價為每股$65。 試問X3年度甲公司應認列此項員工獎酬之薪資費用為何？', '["$(200,000)", "$0", "$100,000", "$200,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
